import clsx from 'clsx';
import { isArray } from 'lodash-es';
import { useContext, useEffect, useMemo, useRef } from 'react';
import { FormattedMessage, useIntl } from 'react-intl';

import Colors from '@dynatrace/strato-design-tokens/colors';
import { useDql } from '@dynatrace-sdk/react-hooks';

import * as styles from './SegmentSelect.sty.js';
import { StratoLoggerContext } from '../../../../core/sdk/StratoLoggerContext.js';
import { useFormFieldMessagesContext } from '../../../../forms/forms-core/hooks/useFormFieldMessagesContext.js';
import { FormFieldMessagesAction } from '../../../../forms/forms-core/state/formfield-messages-state-reducer.js';
import { Select } from '../../../../forms/select/Select.js';
import type { FormControlWithOverlayRef } from '../../../../forms/shared-types.js';
import { Grid } from '../../../../layouts/grid/Grid.js';
import { Link } from '../../../../typography/link/Link.js';
import { Text } from '../../../../typography/text/Text.js';
import { TextEllipsis } from '../../../../typography/text-ellipsis/TextEllipsis.js';
import { type CachedSegment } from '../../contexts/SegmentsCache/SegmentsCache.js';
import {
  UISegmentsContext,
  useSegmentsUIContext,
} from '../../contexts/SegmentsUI/SegmentsUIContext.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';
import {
  convertQueryRecordToStoreSegmentVariables,
  getReadableValue,
} from '../../utils.js';
import { getSegmentHref } from '../segmentManagementHref.js';

type ValueSelectProps = {
  readOnly?: boolean;
  segment: CachedSegment;
  variables?: string[];
  triggerClassName?: string;
};

const dtClientContext = JSON.stringify({
  source: 'SegmentSelector',
  package: '@dynatrace/strato-components',
});

/**
 * ValueSelect component that allows the selection of variables of the segment
 * @internal
 */
export const ValueSelect = (props: ValueSelectProps) => {
  const { triggerClassName, readOnly, segment, variables = [] } = props;
  const variableSelectRef =
    useRef<FormControlWithOverlayRef<HTMLDivElement>>(null);

  const { focusedSegmentId, isTouched } = useContext(UISegmentsContext);
  const { updateUISegment, setArrayIdentifierError } = useSegmentsUIContext();
  const { dispatch: messagesDispatch } = useFormFieldMessagesContext();

  const intl = useIntl();

  const stratoLogger = useContext(StratoLoggerContext);

  const query =
    segment?.segment?.variables !== undefined &&
    segment?.segment?.variables?.type === 'query'
      ? segment.segment.variables.value
      : '';

  const {
    data,
    isLoading: isDqlLoading,
    forceRefetch,
  } = useDql({
    query,
    maxResultRecords: 10_000,
    maxResultBytes: 5_242_880, // 5 MB
    dtClientContext,
  });
  useEffect(() => {
    if (!isDqlLoading && data?.records?.length === 0) {
      stratoLogger?.info(
        'Failed to retrieve segment variables: query returned no records.',
        null,
        {
          query: query.split('|')[0], // log query until first pipe to avoid reporting sensitive data.
          id: segment?.segment?.id,
        },
      );
    }
    // only update when the query changed and is not loading, to prevent multiple logs.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [query, isDqlLoading]);

  /** Checks which variables are already selected but no longer available. */
  const unavailableVariables = useMemo(() => {
    if (data) {
      const firstKey = Object.keys(data.records?.[0] ?? {})[0];
      const dataRecordIds = data.records.map((record) => record?.[firstKey]);

      return variables?.filter((variable) => !dataRecordIds.includes(variable));
    }
  }, [data, variables]);

  /** Filters for all unique variable ids and strips duplicates. */
  const availableVariables = useMemo(() => {
    if (data?.records) {
      let hasArrayIdentifier = false;
      const recordsArray = data?.records
        .map((singleRow) => {
          const firstKey = singleRow ? Object.keys(singleRow)[0] : null;

          if (!singleRow || !firstKey) {
            return null;
          }

          if (isArray(singleRow[firstKey])) {
            hasArrayIdentifier = true;
          }

          return `${singleRow[firstKey]}`;
        })
        .filter((value) => value !== 'null' && value !== null);

      /**
       * The array identifier error can only be detected when the variables are compared to
       * the fetched data, as for all further usages we flatten the array. Therefore, we need
       * to handle the error specifically. As the immediate dispatch would lead to a bad state
       * but we want to avoid to iterate over the variables again, the state update is delayed here.
       */
      queueMicrotask(() => {
        if (hasArrayIdentifier) {
          messagesDispatch?.({
            type: FormFieldMessagesAction.ADDMESSAGE,
            payload: {
              variant: 'error',
              messageType: 'formcontrol',
              id: 'array-identifier',
              validityStateKey: 'customError',
              message: (
                <FormattedMessage
                  {...SEGMENTSELECTOR_MESSAGES.arrayIdentifierError}
                />
              ),
            },
          });
        }
        setArrayIdentifierError(hasArrayIdentifier, segment.segment.id);
      });

      return Array.from(new Set(recordsArray));
    }
  }, [data]);

  const shouldOpen =
    focusedSegmentId === segment.segment.id &&
    variables.length === 0 &&
    isTouched;

  useEffect(() => {
    shouldOpen && variableSelectRef.current?.open();
  }, [shouldOpen]);

  useEffect(() => {
    // initially
    !isTouched && variableSelectRef.current?.validate();
    // we need to validate the select when the variables change
    // this needs to be properly resolved in the select component,
    // as this one needs to validate controlled values automatically.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isTouched, JSON.stringify(variables)]);

  return (
    <Select
      ref={variableSelectRef}
      multiple
      className={styles.variablesSelectCSS}
      required
      readOnly={readOnly || segment?.temporarilyApplied}
      clearable={false}
      onOpenChange={(isOpen) => {
        if (query.length > 0 && isOpen) {
          forceRefetch().catch(() => undefined);
        }
      }}
      value={variables}
      onChange={(newVariables) => {
        if (!newVariables || newVariables.length === 0) {
          updateUISegment(
            {
              ...segment.segment,
              variables: [],
            },
            {
              ...segment.segment,
              variables: [],
            },
          );
          return;
        }

        // get all variable values from the actual data
        const firstKey = Object.keys(data?.records[0] ?? {})[0];
        const dataEnrichedVariables = newVariables
          .map((variable) => {
            return (
              data?.records.find((singleRow) => {
                if (isArray(singleRow?.[firstKey])) {
                  const values = singleRow?.[firstKey].includes(variable);
                  return values;
                }

                return singleRow && singleRow[firstKey] === variable;
              }) ?? null
            );
          })
          .filter((value) => value !== null);

        const segmentVariables = convertQueryRecordToStoreSegmentVariables(
          dataEnrichedVariables,
        );

        if (segmentVariables) {
          updateUISegment(
            {
              ...segment.segment,
              variables: [],
            },
            {
              ...segment.segment,
              variables: segmentVariables,
            },
          );
        }
      }}
      data-dt-name="segment-variable-select"
    >
      <Select.Trigger
        className={clsx(styles.variablesSelectTriggerCSS, triggerClassName)}
        placeholder={intl.formatMessage(
          SEGMENTSELECTOR_MESSAGES.segmentsVariableTriggerPlaceholder,
        )}
      >
        {variables?.length > 0 && (
          <Select.DisplayValue>
            <TextEllipsis>
              {variables
                .map((variable) => getReadableValue(variable, intl))
                .join(', ')}
            </TextEllipsis>
          </Select.DisplayValue>
        )}
      </Select.Trigger>
      <Select.Filter />
      <Select.Content
        loading={isDqlLoading}
        showSelectedOptionsFirst
        width="trigger"
      >
        {!data &&
          variables?.map((variable) => (
            <Select.Option
              key={variable}
              value={variable}
              textValue={getReadableValue(variable, intl) ?? undefined}
            >
              {getReadableValue(variable, intl)}
            </Select.Option>
          ))}
        {unavailableVariables?.map((unlistedVariable) => (
          <Select.Option
            key={unlistedVariable}
            value={unlistedVariable}
            textValue={getReadableValue(unlistedVariable, intl) ?? undefined}
          >
            <Grid
              gridTemplateColumns="auto auto"
              width="100%"
              alignItems="baseline"
            >
              <Text>{getReadableValue(unlistedVariable, intl)}</Text>
              <Text
                textStyle="small"
                style={{
                  color: Colors.Text.Neutral.Subdued,
                  textAlign: 'right',
                  textWrap: 'nowrap',
                }}
              >
                {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.unavailable)}
              </Text>
            </Grid>
          </Select.Option>
        ))}
        {availableVariables?.map((variable) => (
          <Select.Option
            key={variable}
            value={variable}
            textValue={getReadableValue(variable, intl) ?? undefined}
          >
            {/** The option should wrap and not truncate, therefore, it is wrapped in a Text. */}{' '}
            <Text>{getReadableValue(variable, intl)}</Text>
          </Select.Option>
        ))}
        <Select.EmptyState>
          {data?.records.length ? (
            <FormattedMessage
              id="nIw/xeiGNJsj+a+5"
              defaultMessage="No matching values for this segment found."
              description="Hint shown when searching for a segment variable that isn't in the list."
            />
          ) : (
            <FormattedMessage
              defaultMessage="No values for this segment available. You can manage this segment in {link}."
              id="72DlIwYKB9UTEzlA"
              description="Empty state message if no variables for the segment are available."
              values={{
                link: (
                  <Link
                    href={getSegmentHref(segment.segment.id)}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <FormattedMessage
                      defaultMessage="settings"
                      id="u55UYpLvXi//xGEn"
                      description="Link text to segments app in empty state message if no variables for the segment are available."
                    />
                  </Link>
                ),
              }}
            />
          )}
        </Select.EmptyState>
      </Select.Content>
    </Select>
  );
};
